class TrieNode:
    def __init__(self):
        self.children = {}
        self.is_end_of_word = False

class Trie:
    def __init__(self):
        self.root = TrieNode()

    def insert(self, word: str) -> None:
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

class Solution:
    def findAllConcatenatedWordsInADict(self, words: list[str]) -> list[str]:
        trie = Trie()
        for word in words:
            trie.insert(word)

        concatenated_words = []

        for word in words:
            if not word:
                continue

            memo = {} 
            if self._can_form_recursive(word, 0, 0, trie.root, memo):
                concatenated_words.append(word)

        return concatenated_words

    def _can_form_recursive(self, word: str, start_index: int, count: int, trie_root: TrieNode, memo: dict) -> bool:
        if start_index == len(word):
            return count >= 2

        if start_index in memo:
            return memo[start_index]

        current_node = trie_root
        for i in range(start_index, len(word)):
            char = word[i]
            if char not in current_node.children:
                break

            current_node = current_node.children[char]

            if current_node.is_end_of_word:
                if self._can_form_recursive(word, i + 1, count + 1, trie_root, memo):
                    memo[start_index] = True
                    return True

        memo[start_index] = False
        return False
